cd /tmp/sv-4e9ea630ebc6403fa71e72f802b34dc1/advanced-multi-complexity && dotnet package list --format json 2>/dev/null > after-cpm-packages.json && python3 << 'EOF'
import json

baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k, bv, av))
    else:
        unchanged.append((k, bv))

print("=== CHANGES ===")
if changes:
    for (proj, fw, pkg), bv, av in changes:
        status = "Aligned to highest" if bv and av else ("Added" if not bv else "Removed")
        print(f"  {proj} [{fw}]: {pkg}  {bv} -> {av}  ({status})")
else:
    print("  None")

print(f"\n=== UNCHANGED ({len(unchanged)} packages) ===")
for (proj, fw, pkg), v in unchanged:
    print(f"  {proj} [{fw}]: {pkg} = {v}")
EOF

