import json

baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        if bv and av:
            changes.append((k, bv, av, "Aligned to highest version"))
        elif not bv:
            changes.append((k, bv, av, "Added"))
        else:
            changes.append((k, bv, av, "Removed"))
    else:
        unchanged.append((k, bv))

print("=== CHANGES ===")
if changes:
    print(f"{'Project':<16} {'Framework':<8} {'Package':<45} {'Before':<10} {'After':<10} Status")
    print("-" * 120)
    for (proj, fw, pkg), bv, av, status in changes:
        print(f"{proj:<16} {fw:<8} {pkg:<45} {bv or 'N/A':<10} {av or 'N/A':<10} {status}")
else:
    print("  None")

print(f"\n=== UNCHANGED ({len(unchanged)} packages) ===")
print(f"{'Project':<16} {'Framework':<8} {'Package':<45} {'Version':<10}")
print("-" * 80)
for (proj, fw, pkg), v in unchanged:
    print(f"{proj:<16} {fw:<8} {pkg:<45} {v:<10}")
